\begin{algorithmic}
\REQUIRE CAN stream $M = \{m_t = (\text{ID}_t, \text{payload}_t)\}$, window size $W$
\ENSURE Graphs $\mathcal{G} = \{G_t = (V_t, E_t, X_t, y_t)\}$
\FOR{$t = W$ \TO $|M|$}
  \STATE $W_t \leftarrow M[t-W+1 : t]$ \COMMENT{extract window}
  \STATE $\text{source} \leftarrow W_t[:, -3]$; $\text{target} \leftarrow W_t[:, -2]$ \COMMENT{CAN IDs}
  \STATE $\text{edges} \leftarrow \text{stack}(\text{source}, \text{target})$
  \STATE $(\text{unique\_edges}, \text{counts}) \leftarrow \text{unique}(\text{edges})$ \COMMENT{transitions}
  \STATE $V_t \leftarrow \text{unique}(\text{source} \cup \text{target})$ \COMMENT{unique nodes}
  \STATE $\text{node\_map} \leftarrow \{v \mapsto \text{idx} \mid v \in V_t\}$ \COMMENT{node indexing}
  \STATE $E_t \leftarrow [(\text{node\_map}[\text{src}], \text{node\_map}[\text{tgt}])$ for $(\text{src}, \text{tgt}) \in \text{unique\_edges}]$
  \STATE Compute node features: $X_t \in \mathbb{R}^{|V_t| \times 35}$
  \STATE Compute edge features: $F_t \in \mathbb{R}^{|E_t| \times 11}$
  \STATE $y_t \leftarrow 1$ if any attack ID $\in W_t$ else $0$ \COMMENT{label}
\ENDFOR
\end{algorithmic}

\begin{algorithmic}
\REQUIRE Trained VGAE model on normal graphs
\ENSURE Hard-selected training dataset for Stage 2
\STATE Train VGAE on normal graphs until convergence
\FOR{\textbf{each} normal graph $G_i$}
  \STATE $R_i \leftarrow \|\mathbf{A}_i - \hat{\mathbf{A}}_i\|_F^2 / |V_i|^2$ \COMMENT{reconstruction error}
\ENDFOR
\STATE Rank by $R_i$ descending; select top-$k$ as hard negatives
\STATE Combine hard normal samples with all attack samples
\end{algorithmic}
